code = """import json, re, os

# Load packaged data from file
pkg_file = locals()['var_functions.query_db:76']
with open(pkg_file, 'r') as f:
    packages = json.load(f)

# Load mappings (check if it's a file path or direct data)
mapping_val = locals()['var_functions.query_db:42']
if isinstance(mapping_val, str) and 'var_functions' not in str(mapping_val):
    with open(mapping_val, 'r') as f:
        mappings = json.load(f)
else:
    mappings = mapping_val

# Load project info from file
proj_file = locals()['var_functions.query_db:70']
with open(proj_file, 'r') as f:
    project_infos = json.load(f)

# 1. Find latest release version for each package
latest = {}
for pkg in packages:
    name = pkg['Name']
    vi = pkg['VersionInfo']
    
    # Use regex to safely extract values
    ord_match = re.search(r'"Ordinal":\s*(\d+)', vi)
    rel_match = re.search(r'"IsRelease":\s*(true|false)', vi)
    
    if ord_match and rel_match:
        ordinal = int(ord_match.group(1))
        is_rel = rel_match.group(1) == 'true'
        
        if is_rel:
            if name not in latest or ordinal > latest[name]['ordinal']:
                latest[name] = {
                    'version': pkg['Version'],
                    'ordinal': ordinal
                }

# 2. Index mappings by package:version
mapping_index = {}
for m in mappings:
    if m.get('System') == 'NPM':
        key = m['Name'] + ':' + m['Version']
        mapping_index[key] = m['ProjectName']

# 3. Match packages to GitHub projects
matched = []
for name, data in latest.items():
    key = name + ':' + data['version']
    if key in mapping_index:
        matched.append({
            'package': name,
            'version': data['version'],
            'project': mapping_index[key]
        })

# 4. Extract star counts from project info
project_stars = {}
for info in project_infos:
    text = info.get('Project_Information', '')
    
    # Find stars
    star_matches = re.findall(r'(\d{1,3}(?:,\d{3})*)\s+stars', text)
    if star_matches:
        stars = int(star_matches[0].replace(',', ''))
        
        # Find project name
        proj_matches = re.findall(r'project\s+([\w-]+/[\w-]+)', text, re.IGNORECASE)
        if proj_matches:
            project_stars[proj_matches[0]] = stars

# 5. Combine and sort
results = []
for pkg in matched:
    if pkg['project'] in project_stars:
        results.append({
            'package': pkg['package'],
            'version': pkg['version'],
            'project': pkg['project'],
            'stars': project_stars[pkg['project']]
        })

# Sort by stars descending
top_5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

# Print results
print('Top 5 NPM Packages by GitHub Stars:')
for i, pkg in enumerate(top_5, 1):
    print('{}. {} v{} - {} ({} stars)'.format(
        i, pkg['package'], pkg['version'], pkg['project'], pkg['stars']
    ))

# Return JSON result
output = {'top_packages': top_5}
print('__RESULT__:')
print(json.dumps(output))"""

